public int subarraysDivByK(int[] nums, int k) {
    Map<Integer, Integer> counts = new HashMap<>();
    counts.put(0, 1);
    int sum = 0, result = 0;

    for (int num : nums) {
        sum += num;
        int mod = ((sum % k) + k) % k;
        result += counts.getOrDefault(mod, 0);
        counts.put(mod, counts.getOrDefault(mod, 0) + 1);
    }

    return result;
}
```

